ALGORITHM SolarEnergyCalculation
BEGIN
 INPUT panelPowerWatts // Panel rated power in Watts
 INPUT panelEfficiency // Panel efficiency as decimal (e.g., 0.20)
 INPUT sunHoursPerDay // Average peak sun hours
 INPUT systemLosses // Total system losses (wiring, inverter, etc.)

 // Calculate theoretical daily generation
 peakPowerWatts = panelPowerWatts * panelEfficiency
 theoreticalDailykWh = (peakPowerWatts * sunHoursPerDay) / 1000

 // Apply system losses
 actualDailykWh = theoreticalDailykWh * (1 - systemLosses)

 // Calculate annual generation
 annualkWh = actualDailykWh * 365

 OUTPUT actualDailykWh
 OUTPUT annualkWh

 // Example: 300W panel, 20% efficiency, 5 sun hours, 20% losses
 // peakPower = 300 * 0.20 = 60W
 // theoretical = 60 * 5 / 1000 = 0.3 kWh
 // actual = 0.3 * 0.80 = 0.24 kWh/day
END

ALGORITHM CalculateOptimalAngle
BEGIN
 INPUT latitude // Location latitude in degrees

 // Winter optimal angle (for best winter performance)
 winterAngle = latitude + 15

 // Summer optimal angle (for best summer performance) summerAngle = latitude - 15

 // Year-round optimal angle (average) yearlyAngle = latitude

 // Output angles for different seasons OUTPUT "Winter optimal: " + winterAngle + " degrees"
 OUTPUT "Summer optimal: " + summerAngle + " degrees" OUTPUT "Year-round optimal: " + yearlyAngle + " degrees"

 // For latitude = 20°: // Winter: 35°, Summer: 5°, Year-round: 20°
END
